import os

import litgen
from srcmlcpp.scrml_warning_settings import WarningType


THIS_DIR = os.path.dirname(__file__)
PYDEF_DIR = THIS_DIR
STUB_DIR = THIS_DIR + "/../../../bindings/imgui_bundle/"

MAIN_DIR = THIS_DIR + "/../"



# ---------------------------------------------------------------------------
# Source preprocess (runs before litgen sees the headers)
#
# Used instead of #ifdef IMGUI_BUNDLE_PYTHON_UNSUPPORTED_API blocks in the
# upstream header, so we don't carry rebase friction every time we sync.
#
# Each cut uses sentinel comments as boundaries and raises RuntimeError if
# a sentinel disappears in a future update — silent breakage becomes a loud
# regeneration failure with a clear pointer to the helper that needs review.
# ---------------------------------------------------------------------------


def _replace_color_count(code: str) -> str:
    # srcML bug: parentheses inside template arguments break the parser.
    # Use C-style cast instead. See https://github.com/srcML/srcML/issues/2327
    return code.replace("static_cast<size_t>(Color::count)", "(size_t)(Color::count)")


def _strip_language_internals(code: str) -> str:
    """Reduce `struct Language { ... };` to just its static factories.

    The Language struct exposes std::function<Iterator(...)> tokenizer
    callbacks and std::unordered_set<std::string> keyword/identifier sets
    that are not usefully bindable in Python (Iterator wraps a glyph
    pointer; writing a tokenizer from Python is impractical). The plain
    config fields (name, comment markers, string delimiters, ...) are not
    useful without the callbacks, so we hide the whole body and keep only
    the static `static const Language* C/Cpp/Python/...()` factories,
    which are the actual user-facing API.

    The cut runs from `struct Language {` up to (but not including) the
    `// predefined language definitions` sentinel comment. If either
    marker disappears in a future upstream update, this function raises
    so regeneration fails loudly rather than silently producing broken
    bindings.
    """
    open_marker = "struct Language {"
    sentinel = "// predefined language definitions"

    # litgen calls the preprocess on every snippet it round-trips through
    # srcML (constructor wrapper signatures, etc.), not only on whole files.
    # We tell "full file pass" from "small snippet" by looking for a stable
    # landmark that's only in the full TextEditor.h: the main class line.
    file_landmark = "class IMGUI_API TextEditor"
    is_full_file = file_landmark in code

    start = code.find(open_marker)
    if start < 0:
        if is_full_file:
            raise RuntimeError(
                "ImGuiColorTextEdit preprocess: could not find "
                f"`{open_marker}` while processing the full TextEditor.h. "
                "The Language struct may have been renamed or moved; review "
                "_strip_language_internals() in "
                "generate_imgui_color_text_edit.py."
            )
        # Small snippet that doesn't contain the marker — nothing to strip.
        return code

    body_start = start + len(open_marker)
    sentinel_at = code.find(sentinel, body_start)
    if sentinel_at < 0:
        if is_full_file:
            raise RuntimeError(
                "ImGuiColorTextEdit preprocess: could not find sentinel "
                f"`{sentinel}` inside `struct Language` in TextEditor.h. "
                "Upstream likely reworded the comment that precedes the "
                "static factory methods. Either restore the sentinel or "
                "pick a new one and update _strip_language_internals()."
            )
        # Synthetic small snippet that mentions Language (e.g. a constructor
        # wrapper generated by litgen) — leave it alone.
        return code

    return code[:body_start] + "\n\t\t" + code[sentinel_at:]


def preprocess(code: str) -> str:
    code = _replace_color_count(code)
    code = _strip_language_internals(code)
    return code


def main():
    print("autogenerate_imgui_color_text_edit")
    output_cpp_pydef_file = PYDEF_DIR + "/pybind_imgui_color_text_edit.cpp"
    output_stub_pyi_file = STUB_DIR + "/imgui_color_text_edit.pyi"

    # Configure options
    options = litgen.LitgenOptions()
    options.use_nanobind()
    options.fn_params_type_replacements.add_replacements([(r"\bImVec2\b", "ImVec2Like"), (r"\bImVec4\b", "ImVec4Like")])
    options.srcmlcpp_options.ignored_warnings = [
        WarningType.LitgenClassMemberSkipBitfield
    ]
    options.fn_return_force_policy_reference_for_references__regex = r".*"
    options.fn_return_force_policy_reference_for_pointers__regex = r".*"

    # Exclude void* userData fields from Decorator / PopupData / AutoComplete*
    # (opaque pointers carry no Python lifetime info).
    options.member_exclude_by_name__regex = r"^userData$"

    # These types exist only to support writing custom language tokenizers,
    # which is impractical from Python (Iterator wraps a Glyph*; the tokenizer
    # callbacks live on the (already-stripped) Language struct).
    options.class_exclude_by_name__regex = r"^(Glyph|Iterator|CodePoint|AutoCompleteConfig|AutoCompleteState)$"
    options.enum_exclude_by_name__regex = r"^BreakOption$"

    # Some structs contain a private member named main, which confuses srcML.
    # Inline class-member declarations (`} cursors;` etc.) are not supported by srcML.
    # Iterator operators are not bindable in Python.
    options.srcmlcpp_options.ignored_warning_parts += [
        "main =", "operator*", "operator->", "operator++",
        "} cursors;", "} document;", "} transactions;",
        "} colorizer;", "} bracketeer;", "} autocomplete;",
        "} config;", "} typeSetter;", "} miniMap;",  "} lineFold;",
        "} diff;", "} integratedView;", "} sideBySideView;"
    ]

    # Exclude void* per-line state APIs entirely. Python users who need
    # per-line state should drive their own dict from the change callback;
    # demo_text_edit.py's breakpoint tab already does this.
    options.fn_exclude_by_name__regex = (
        r"^(SetInsertor|SetDeletor|SetUserData|GetUserData|IterateUserData"
        # SetImGuiContext takes a forward-declared ImGuiContext*; only useful
        # for DLL builds (not recommended by upstream).
        r"|SetImGuiContext"
        # Autocomplete API depends on AutoCompleteConfig/State which we don't
        # currently bind (callback + chrono + Language* tangle). Revisit later.
        r"|SetAutoCompleteConfig|SetAutoCompleteSuggestions"
        r")$"
    )

    options.srcmlcpp_options.code_preprocess_function = preprocess

    generator = litgen.LitgenGenerator(options)
    generator.process_cpp_file(MAIN_DIR + "/ImGuiColorTextEdit/TextEditor.h")
    generator.process_cpp_file(MAIN_DIR + "/ImGuiColorTextEdit/TextDiff.h")

    generator.write_generated_code(
        output_cpp_pydef_file=output_cpp_pydef_file,
        output_stub_pyi_file=output_stub_pyi_file,
    )


if __name__ == "__main__":
    main()
